-- Grid Designs & BOMs — schema for the shared Supabase (anansi chat DB).
-- GENERATED by scripts/gen_schema.py — do not edit by hand.
-- Tables are prefixed gd_ and live in the public schema alongside anansi's.
-- Run in the Supabase SQL editor.
--
-- Note: AppSheet stored most values as free text; columns flagged numeric/
-- boolean in db/column_map.py are typed accordingly, the rest stay text.
-- FK relationships are indexed and documented but NOT hard-enforced in v1
-- (historical data has dangling refs).

-- ── Organizations (Admin) ────────────────────
CREATE TABLE IF NOT EXISTS gd_organizations (
    id                                 text PRIMARY KEY,
    name                               text,
    active                             boolean DEFAULT true,
    created_by                         text,
    created_at                         timestamptz DEFAULT now()
);

-- ── Users (Admin) ────────────────────
CREATE TABLE IF NOT EXISTS gd_users (
    id                                 text PRIMARY KEY,
    name                               text,
    organization                       text,
    email                              text,
    can                                text,
    active                             boolean DEFAULT true
);
CREATE INDEX IF NOT EXISTS gd_users_organization_idx ON gd_users (organization);  -- FK -> gd_organizations(id)

-- ── Grids (Sites) ────────────────────
CREATE TABLE IF NOT EXISTS gd_grids (
    id                                 text PRIMARY KEY,
    name                               text,
    community                          text,
    stage                              text,
    created_at                         timestamptz DEFAULT now(),
    active                             boolean DEFAULT true
);

-- ── Grid Coordinates (Sites) ────────────────────
CREATE TABLE IF NOT EXISTS gd_grid_coords (
    id                                 text PRIMARY KEY,
    grid                               text,
    coordinate                         text,
    active                             boolean DEFAULT true
);
CREATE INDEX IF NOT EXISTS gd_grid_coords_grid_idx ON gd_grid_coords (grid);  -- FK -> gd_grids(id)

-- ── Components (Catalogue) ────────────────────
CREATE TABLE IF NOT EXISTS gd_components (
    id                                 text PRIMARY KEY,
    name                               text,
    name_in_french                     text,
    counting_unit                      text,
    component_type                     text,
    source                             text,
    who_procures                       text,
    unit_cost_usd                      numeric,
    unit_cost_ngn                      numeric,
    spec1_name                         text,
    spec1_value                        text,
    spec1_unit                         text,
    spec2_name                         text,
    spec2_value                        text,
    spec2_unit                         text,
    spec3_name                         text,
    spec3_value                        text,
    spec3_unit                         text,
    contingency_pct                    numeric,
    created_at                         timestamptz DEFAULT now(),
    active                             boolean DEFAULT true,
    notes                              text,
    do_not_miss                        boolean,
    ddp_cost                           numeric,
    projected_cost                     numeric,
    cost_confidence                    text,
    num_purchases                      numeric,
    cost_projected_at                  timestamptz
);

-- ── Subassemblies (Catalogue) ────────────────────
CREATE TABLE IF NOT EXISTS gd_subassemblies (
    id                                 text PRIMARY KEY,
