);
CREATE INDEX IF NOT EXISTS gd_subassemblies_main_component_idx ON gd_subassemblies (main_component);  -- FK -> gd_components(id)

-- ── Subassembly Components (Catalogue) ────────────────────
CREATE TABLE IF NOT EXISTS gd_subassembly_components (
    id                                 text PRIMARY KEY,
